 92	  {
 93	    breakpoint = Breakpoint.Xl,
 94	    lang,
 95	  }: { breakpoint?: Breakpoint; lang?: 'fr' } = {},
 96	): string => {
 97	  const Stub = createRoutesStub([
 98	    {
 99	      id: 'root',
100	      // Mirror the app's optional leading `:lang?` segment so `useLocale`
101	      // (which reads `params.lang`) resolves `/fr` → French, `/` → English.
102	      path: ':lang?',
103	      Component: () => (
104	        <LocalizationProvider
105	          translation={translations[lang === 'fr' ? 'fr' : 'en']}
106	        >
